async function resolveBuilder (nuxt: Nuxt): Promise<NuxtBuilder> {
  const source = typeof nuxt.options.builder === 'string'
    ? await loadBuilder(nuxt, nuxt.options.builder)
    : nuxt.options.builder

  // Wrap `bundle` so the `build:error` hook fires for any builder, including
  // user-supplied ones, without each caller having to remember to do it.
  return {
    ...source,
    async bundle (nuxt) {
      try {
        await source.bundle(nuxt)
      } catch (error: any) {
        await nuxt.callHook('build:error', error)
        throw error
      }
    },
  }
}

private transformDynamicImports (source: string): string {
  let transformed = source
  let needsHelperImport = false

  // Transform webpack-style dynamic imports to rollup-compatible ones
  transformed = transformed.replace(DYNAMIC_IMPORT_REPLACE_RE, (match, filename) => {
    needsHelperImport = true
    // Generate a rollup-compatible dynamic import using the module ID
    return `_rollupDynamicImport(${filename}).then`
  })

  // Add import statement at the top if we made any transformations
  if (needsHelperImport && !transformed.includes(HELPER_IMPORT)) {
    transformed = HELPER_IMPORT + transformed
  }

  return transformed
}

function baseAlias (ctx: WebpackConfigContext) {
  ctx.alias = {
    '#app': ctx.options.appDir,
    [basename(ctx.nuxt.options.dir.assets)]: resolve(ctx.nuxt.options.srcDir, ctx.nuxt.options.dir.assets),
    ...ctx.options.alias,
    ...ctx.alias,
  }
  if (ctx.isClient) {
    ctx.alias['nitro/runtime-config'] = resolve(ctx.nuxt.options.buildDir, 'nitro.client.mjs')
    // TODO: remove in v5
    ctx.alias['#internal/nitro'] = resolve(ctx.nuxt.options.buildDir, 'nitro.client.mjs')
    ctx.alias['nitropack/runtime'] = resolve(ctx.nuxt.options.buildDir, 'nitro.client.mjs')
  }
}

async function createdStyleRule (lang: string, test: RegExp, processorLoader: any, ctx: WebpackConfigContext) {
  const styleLoaders = [
    await createPostcssLoadersRule(ctx),
    processorLoader,
  ].filter(Boolean)

  ctx.userConfig.loaders.css.importLoaders =
    ctx.userConfig.loaders.cssModules.importLoaders =
      styleLoaders.length

  const cssLoaders = createCssLoadersRule(ctx, ctx.userConfig.loaders.css)
  const cssModuleLoaders = createCssLoadersRule(ctx, ctx.userConfig.loaders.cssModules)

  return {
    test,
    oneOf: [
      // This matches <style module>
      {
        resourceQuery: /module/,
        use: cssModuleLoaders.concat(styleLoaders),
      },
      // This matches plain <style> or <style scoped>
      {
        use: cssLoaders.concat(styleLoaders),
      },
    ],
  }
}

function _calculatePosition (
  to: RouteLocationNormalized,
  from: RouteLocationNormalized,
  savedPosition: ScrollPosition | null,
  defaultHashScrollBehaviour: ScrollBehavior,
): ScrollPosition {
  // By default when the returned position is falsy or an empty object, vue-router will retain the current scroll position
  // savedPosition is only available for popstate navigations (back button)
  if (savedPosition) {
    return savedPosition
  }

  // Scroll to the element specified in the URL hash, if present
  if (to.hash) {
    return {
      el: to.hash,
      top: _getHashElementScrollMarginTop(to.hash),
      behavior: isChangingPage(to, from) ? defaultHashScrollBehaviour : 'instant',
    }
  }

  return {
    left: 0,
    top: 0,
  }
}

async function handleFormatMessage(message) {
  if (!_prettier) {
    const [prettierModule, ...plugins] = await Promise.all([
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/standalone.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/babel.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/estree.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/html.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/markdown.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/typescript.mjs')
    ])
    _prettier = prettierModule
    _plugins = plugins
  }

  const { options, source } = message
  return _prettier.format(source, {
    parser: 'markdown',
    plugins: _plugins,
    ...options
  })
}

function checkScrollPosition() {
  if (!parent.value) {
    return
  }

  const scrollPosition = parent.value.scrollTop + parent.value.clientHeight
  const scrollHeight = parent.value.scrollHeight
  const threshold = 100

  showAutoScroll.value = (scrollHeight - scrollPosition) >= threshold

  // Detect user scrolling up
  if (parent.value.scrollTop < lastScrollTop.value) {
    userScrolledUp.value = true
  } else if ((scrollHeight - scrollPosition) < threshold) {
    userScrolledUp.value = false
  }

  lastScrollTop.value = parent.value.scrollTop
}

export function createMarkdownStringifier(options: MDCStringifyOptions = {}) {
  const processor = createStringifyProcessor(options)

  async function stringify(value: any, data: Record<string, any> = {}): Promise<string> {
    const result = await processor.process({ value: JSON.stringify(value) })

    // Stringify front matter returns empty string if no data is provided
    if (Object.keys(data).length) {
      return stringifyFrontMatter(data, result.value as string, options.frontMatter?.options)
    }

    return result.value as string
  }

  return stringify
}

async (e) => {
  const runtimeConfig = useRuntimeConfigNuxtRobots(e)
  const { indexable, hints } = getSiteRobotConfig(e)
  const siteConfig = getSiteConfig(e)
  // @ts-expect-error Nuxt typed routes cause excessive type depth with $fetch
  const robotsTxt: string = await e.$fetch('/robots.txt', {
    query: getQuery(e),
  })
  const parsed = validateRobots(parseRobotsTxt(robotsTxt))
  return {
    robotsTxt,
    indexable,
    hints,
    runtimeConfig,
    siteConfig: {
      url: siteConfig.url,
      env: siteConfig.env,
      indexable: siteConfig.indexable,
    },
    validation: {
      errors: parsed.errors,
      warnings: parsed.warnings,
      groups: parsed.groups.length,
      sitemaps: parsed.sitemaps,
    },
  }
}

(context, pipe, size) => {
  let [width, height] = String(size).split("x").map(Number);
  if (!width) {
    return;
  }
  if (!height) {
    height = width;
  }
  // sharp's `withoutEnlargement` doesn't respect the requested aspect ratio, so we need to do it ourselves
  if (!context.enlarge) {
    const clamped = clampDimensionsPreservingAspectRatio(context.meta, {
      width,
      height,
    });
    width = clamped.width;
    height = clamped.height;
  }
  return pipe.resize(width, height, {
    fit: context.fit,
    position: context.position,
    background: context.background,
    kernel: context.kernel,
  });
}

export function clampDimensionsPreservingAspectRatio(
  sourceDimensions: ImageMeta,
  desiredDimensions: { width: number; height: number },
) {
  const desiredAspectRatio = desiredDimensions.width / desiredDimensions.height;
  let { width, height } = desiredDimensions;
  if (sourceDimensions.width && width > sourceDimensions.width) {
    width = sourceDimensions.width;
    height = Math.round(sourceDimensions.width / desiredAspectRatio);
  }
  if (sourceDimensions.height && height > sourceDimensions.height) {
    height = sourceDimensions.height;
    width = Math.round(sourceDimensions.height * desiredAspectRatio);
  }

  return { width, height };
}

async function generateTLSCert(options: TLSCertOptions): Promise<Certificate> {
  // Certificate Attributes (https://git.io/fptna)
  const { attributes, extensions } = createCertificateInfo(options);

  const ca = forge.pki.certificateFromPem(options.signingKeyCert!);

  return await generateCert({
    bits: options.bits,
    subject: attributes,
    issuer: ca.subject.attributes,
    extensions,
    validityDays: options.validityDays || 1,
    signingKey: options.signingKey,
    signingKeyPassphrase: options.signingKeyPassphrase,
    passphrase: options.passphrase,
  });
}

export function removeRoute<T>(ctx: RouterContext<T>, method: string, path: string): void {
  const groupExpanded = expandGroupDelimiters(path);
  if (groupExpanded) {
    for (const expandedPath of groupExpanded) {
      removeRoute(ctx, method, expandedPath);
    }
    return;
  }

  path = encodeEscapes(path);

  const segments = splitPath(path);

  const modExpanded = expandModifiers(segments);
  if (modExpanded) {
    for (const expandedPath of modExpanded) {
      removeRoute(ctx, method, expandedPath);
    }
    return;
  }

  _remove(ctx.root, method || "", segments, 0);
}
